class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        int n = num.length();
        List<Integer> result = new ArrayList<>();
        int prev = 0, curr = 1;

        for (int i = 0; i < n; i++) {
            int digit = Character.getNumericValue(num.charAt(i));
            if (digit == '0') {
                if (i == n - 1) {
                    result.add(prev);
                    result.add(curr);
                    return result;
                }
                prev = curr;
                curr = prev + curr;
            } else {
                result.add(prev);
                prev = curr;
                curr = prev + digit;
            }
        }
        result.add(prev);
        result.add(curr);
        return result;
    }
}
